import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as t,o as p,c as o,a as n,b as e,d as c,e as l}from"./app-706bfe03.js";const u={},i=l(`<h1 id="diff-算法" tabindex="-1"><a class="header-anchor" href="#diff-算法" aria-hidden="true">#</a> diff 算法</h1><p>diff 算法是一种通过同层的树节点进行比较的高效算法，算法的整体策略是：深度优先，同层比较。</p><p>比较只会在同层级进行, 不会跨层级比较。</p><img class="img-mid" src="https://static001.infoq.cn/resource/image/91/54/91e9c9519a11caa0c5bf70714383f054.png" style="zoom:50%;"><p>算法的核心在于，给定一组 vnode 节点，如何通过较少的创建，主要通过移动节点，得到期望的排列结果。也就是在树节点的某一层中，旧节点如何高效地变成新节点。</p><h2 id="vue2-diff" tabindex="-1"><a class="header-anchor" href="#vue2-diff" aria-hidden="true">#</a> Vue2 diff</h2><p>在 vue2 的 diff 比较过程中，循环从两边向中间比较。</p><img class="img-mid" src="https://static001.infoq.cn/resource/image/2d/ec/2dcd6ad5cf82c65b9cfc43a27ba1e4ec.png" style="zoom:50%;"><p>比较过程可以分三步：</p><ol><li>两列表两端共四个节点，上下两两比较，找出相同节点</li><li>如果第一步找不到，则在旧列表中找新列表的第一个节点</li><li>当某一列表遍历完成，处理剩余的节点</li></ol><h3 id="两端对比" tabindex="-1"><a class="header-anchor" href="#两端对比" aria-hidden="true">#</a> 两端对比</h3><img class="img-mid" src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h4h342rtspj20ct08ywes.jpg" style="zoom:90%;"><p>第一步中上下 4 个节点上下比较，共 4 种情况，</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">isUndef</span><span class="token punctuation">(</span>oldStartVnode<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token comment">/* ... */</span><span class="token punctuation">}</span>
<span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">isUndef</span><span class="token punctuation">(</span>oldEndVnode<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token comment">/* ... */</span><span class="token punctuation">}</span>
<span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">sameVnode</span><span class="token punctuation">(</span>oldStartVnode<span class="token punctuation">,</span> newStartVnode<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token comment">/* ... */</span><span class="token punctuation">}</span>
<span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">sameVnode</span><span class="token punctuation">(</span>oldEndVnode<span class="token punctuation">,</span> newEndVnode<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token comment">/* ... */</span><span class="token punctuation">}</span>
<span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">sameVnode</span><span class="token punctuation">(</span>oldStartVnode<span class="token punctuation">,</span> newEndVnode<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token comment">/* ... */</span><span class="token punctuation">}</span>
<span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">sameVnode</span><span class="token punctuation">(</span>oldEndVnode<span class="token punctuation">,</span> newStartVnode<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token comment">/* ... */</span><span class="token punctuation">}</span>
<span class="token keyword">else</span> <span class="token punctuation">{</span><span class="token comment">/* ... */</span><span class="token punctuation">}</span>
</code></pre></div><p>如果 vnode 相同，则指针做相应左移或右移。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">sameVnode</span><span class="token punctuation">(</span>oldStartVnode<span class="token punctuation">,</span> newStartVnode<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// 左端相同</span>
  <span class="token function">patchVnode</span><span class="token punctuation">(</span>oldStartVnode<span class="token punctuation">,</span> newStartVnode<span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">)</span> <span class="token comment">// 深度优先</span>
	<span class="token operator">++</span>oldStartIdx
	<span class="token operator">++</span>newStartIdx
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">sameVnode</span><span class="token punctuation">(</span>oldEndVnode<span class="token punctuation">,</span> newEndVnode<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// 右端相同</span>
  <span class="token function">patchVnode</span><span class="token punctuation">(</span>oldEndVnode<span class="token punctuation">,</span> newEndVnode<span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">)</span>
	<span class="token operator">--</span>oldEndIdx
	<span class="token operator">--</span>newEndIdx
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">sameVnode</span><span class="token punctuation">(</span>oldStartVnode<span class="token punctuation">,</span> newEndVnode<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// Vnode moved right</span>
  <span class="token function">patchVnode</span><span class="token punctuation">(</span>oldStartVnode<span class="token punctuation">,</span> newEndVnode<span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">)</span>
  <span class="token comment">// oldStart = newEnd 该节点应该放在最后面，即 oldEnd 后面</span>
  <span class="token comment">// 用 insertBefore(nextSibling) 实现 insertAfter</span>
  nodeOps<span class="token punctuation">.</span><span class="token function">insertBefore</span><span class="token punctuation">(</span>parentElm<span class="token punctuation">,</span> oldStartVnode<span class="token punctuation">.</span>elm<span class="token punctuation">,</span> nodeOps<span class="token punctuation">.</span><span class="token function">nextSibling</span><span class="token punctuation">(</span>oldEndVnode<span class="token punctuation">.</span>elm<span class="token punctuation">)</span><span class="token punctuation">)</span>
	<span class="token operator">++</span>oldStartIdx
	<span class="token operator">--</span>newEndIdx
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">sameVnode</span><span class="token punctuation">(</span>oldEndVnode<span class="token punctuation">,</span> newStartVnode<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// Vnode moved left</span>
  <span class="token function">patchVnode</span><span class="token punctuation">(</span>oldEndVnode<span class="token punctuation">,</span> newStartVnode<span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">)</span>
  <span class="token comment">// oldEnd = newStart 该节点应该放在最前面，即 oldStart 前面</span>
  nodeOps<span class="token punctuation">.</span><span class="token function">insertBefore</span><span class="token punctuation">(</span>parentElm<span class="token punctuation">,</span> oldEndVnode<span class="token punctuation">.</span>elm<span class="token punctuation">,</span> oldStartVnode<span class="token punctuation">.</span>elm<span class="token punctuation">)</span>
	<span class="token operator">--</span>oldEndIdx
	<span class="token operator">++</span>newStartIdx
<span class="token punctuation">}</span>
</code></pre></div><p>如果两端交叉比较后没有找到相同节点，则在中间节点遍历寻找。</p><h3 id="中间遍历寻找" tabindex="-1"><a class="header-anchor" href="#中间遍历寻找" aria-hidden="true">#</a> 中间遍历寻找</h3><p>如果两端没有找到相同节点，则在旧节点中遍历寻找与 newStartVnode 相同的节点</p><ul><li>如果找到，则将其移动到 oldStartVnode 之前</li><li>如果没有，则新建节点并放在 oldStartVnode 之前</li></ul><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code>idxInOld <span class="token operator">=</span> <span class="token function">isDef</span><span class="token punctuation">(</span>newStartVnode<span class="token punctuation">.</span>key<span class="token punctuation">)</span>
  <span class="token operator">?</span> oldKeyToIdx<span class="token punctuation">[</span>newStartVnode<span class="token punctuation">.</span>key<span class="token punctuation">]</span>
  <span class="token operator">:</span> <span class="token function">findIdxInOld</span><span class="token punctuation">(</span>newStartVnode<span class="token punctuation">,</span> oldCh<span class="token punctuation">,</span> oldStartIdx<span class="token punctuation">,</span> oldEndIdx<span class="token punctuation">)</span> <span class="token comment">// 中间遍历</span>

<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">isUndef</span><span class="token punctuation">(</span>idxInOld<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// 中间遍历也没找到，则新建节点并放在 oldStartVnode 之前</span>
  <span class="token function">createElm</span><span class="token punctuation">(</span>newStartVnode<span class="token punctuation">,</span> <span class="token operator">...</span> oldStartVnode<span class="token punctuation">.</span>elm<span class="token punctuation">)</span>
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
  vnodeToMove <span class="token operator">=</span> oldCh<span class="token punctuation">[</span>idxInOld<span class="token punctuation">]</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">sameVnode</span><span class="token punctuation">(</span>vnodeToMove<span class="token punctuation">,</span> newStartVnode<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token function">patchVnode</span><span class="token punctuation">(</span>vnodeToMove<span class="token punctuation">,</span> newStartVnode<span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">)</span>
    oldCh<span class="token punctuation">[</span>idxInOld<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token keyword">undefined</span>
    nodeOps<span class="token punctuation">.</span><span class="token function">insertBefore</span><span class="token punctuation">(</span>parentElm<span class="token punctuation">,</span> vnodeToMove<span class="token punctuation">.</span>elm<span class="token punctuation">,</span> oldStartVnode<span class="token punctuation">.</span>elm<span class="token punctuation">)</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token comment">// key 相同但不是相同元素，也重新创建</span>
    <span class="token function">createElm</span><span class="token punctuation">(</span>newStartVnode<span class="token punctuation">,</span> insertedVnodeQueue<span class="token punctuation">,</span> parentElm<span class="token punctuation">,</span> oldStartVnode<span class="token punctuation">.</span>elm<span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
newStartVnode <span class="token operator">=</span> newCh<span class="token punctuation">[</span><span class="token operator">++</span>newStartIdx<span class="token punctuation">]</span>
</code></pre></div><h3 id="处理剩余节点" tabindex="-1"><a class="header-anchor" href="#处理剩余节点" aria-hidden="true">#</a> 处理剩余节点</h3><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>oldStartIdx <span class="token operator">&gt;</span> oldEndIdx<span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// 旧节点遍历完，直接创建其余新节点</span>
  <span class="token function">addVnodes</span><span class="token punctuation">(</span>parentElm<span class="token punctuation">,</span> refElm<span class="token punctuation">,</span> newCh<span class="token punctuation">,</span> newStartIdx<span class="token punctuation">,</span> newEndIdx<span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>newStartIdx <span class="token operator">&gt;</span> newEndIdx<span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// 新节点遍历完，直接删除其余旧节点</span>
  <span class="token function">removeVnodes</span><span class="token punctuation">(</span>oldCh<span class="token punctuation">,</span> oldStartIdx<span class="token punctuation">,</span> oldEndIdx<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre></div><h2 id="vue3-diff" tabindex="-1"><a class="header-anchor" href="#vue3-diff" aria-hidden="true">#</a> vue3 diff</h2><p>Vue3 的 diff 算法：</p><ol><li>预处理</li><li>找出新节点在旧节点中的位置 source 列表，source 列表中的最长递增子序列是不需要移动的</li><li>移动、创建、删除其余节点</li></ol><h3 id="预处理" tabindex="-1"><a class="header-anchor" href="#预处理" aria-hidden="true">#</a> 预处理</h3><p>在 vue2 的 diff 算法中，两端交叉对比共有 5 中情况，预处理就是将其中</p><ul><li>oldStart = newStart</li><li>oldEnd = newEnd</li></ul><p>这两种情况先处理。</p><p>它们是不需要移动的，只需调用 patchVnode 对子树进行 diff 算法，毕竟 diff 算法是深度优先的。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>oldStart <span class="token operator">==</span> newStart<span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// 左端相同</span>
  <span class="token function">diff</span><span class="token punctuation">(</span>oldStart<span class="token punctuation">,</span> newStart<span class="token punctuation">)</span> <span class="token comment">// 深度优先</span>
	oldStartIdx<span class="token operator">++</span>
	newStartIdx<span class="token operator">++</span>
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>oldEnd <span class="token operator">==</span> newEnd<span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// 右端相同</span>
  <span class="token function">diff</span><span class="token punctuation">(</span>oldEnd<span class="token punctuation">,</span> newEnd<span class="token punctuation">)</span>
	oldEndIdx<span class="token operator">--</span>
	newEndIdx<span class="token operator">--</span>
<span class="token punctuation">}</span>
</code></pre></div><h3 id="source" tabindex="-1"><a class="header-anchor" href="#source" aria-hidden="true">#</a> source</h3><p>source 是一个数组，存储的是新列表节点在旧列表中的下标，如果不存在则为 -1。</p><img class="img-mid" src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h4qgt9evr8j20id08xjrr.jpg" style="zoom:80%;"><p>source 的作用是找出其中的最长递增子序列 LIS，它们是不需要移动的。</p><p><em>具体如何求一个数组的最长递增子序列后文会介绍，它是一个动态规划问题。</em></p><p><strong>从后遍历 source 数组</strong>，有三种情况：</p><ul><li><p>值为 -1：表示这是一个新节点，直接创建并插入尾部</p></li><li><p>值是 LIS 中的值：说明这个节点不需要移动</p></li><li><p>值不是 LIS 中的值：这个节点需要移动，我们需要将旧列表中这个 index 的节点放到尾部</p><p>比如上图中的 B 节点的 source 值为 1，且不是 LIS 中的值，那么 <code>old[1]</code> 需要被移动到尾部</p></li></ul><h3 id="最长递增子序列" tabindex="-1"><a class="header-anchor" href="#最长递增子序列" aria-hidden="true">#</a> 最长递增子序列</h3><img class="img-mid" src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h4txj8ewqaj20gp05l3yj.jpg" style="zoom:80%;"><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">/* 动态规划：
	 dp 数组表示当前位置到 nums 末尾的最长递增子序列长度
   dp 初始化为 1，因为一个字符最长序列就是本身
   当前位置的 dp 值，等于往后各递增数字的 dp 值中的最大值 */</span>

<span class="token comment">/* nums 10,9,2,5,3,8,7,13
    dp           3 2 2 1 */</span>
<span class="token keyword">function</span> <span class="token function">lengthOfLIS</span><span class="token punctuation">(</span><span class="token parameter">nums</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> dp <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Array</span><span class="token punctuation">(</span>nums<span class="token punctuation">.</span>length<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">fill</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span>

  <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> i <span class="token operator">=</span> nums<span class="token punctuation">.</span>length <span class="token operator">-</span> <span class="token number">1</span><span class="token punctuation">;</span> i <span class="token operator">&gt;=</span> <span class="token number">0</span><span class="token punctuation">;</span> i<span class="token operator">--</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">let</span> max <span class="token operator">=</span> <span class="token number">1</span> <span class="token comment">// 当前 dp 最大值</span>
    <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> j <span class="token operator">=</span> i<span class="token punctuation">;</span> j <span class="token operator">&lt;</span> nums<span class="token punctuation">.</span>length<span class="token punctuation">;</span> j<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">if</span> <span class="token punctuation">(</span>nums<span class="token punctuation">[</span>i<span class="token punctuation">]</span> <span class="token operator">&lt;</span> nums<span class="token punctuation">[</span>j<span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// 比当前值小，不能加入递增序列</span>
        max <span class="token operator">=</span> Math<span class="token punctuation">.</span><span class="token function">max</span><span class="token punctuation">(</span>max<span class="token punctuation">,</span> dp<span class="token punctuation">[</span>j<span class="token punctuation">]</span> <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">// dp[j] + 1 表示把 nums[i] 加入序列</span>
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
    dp<span class="token punctuation">[</span>i<span class="token punctuation">]</span> <span class="token operator">=</span> max
  <span class="token punctuation">}</span>

  <span class="token comment">// 求出 dp 中的最大值</span>
  <span class="token keyword">let</span> ans <span class="token operator">=</span> <span class="token operator">-</span><span class="token number">1</span>
  <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">const</span> val <span class="token keyword">of</span> dp<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    ans <span class="token operator">=</span> Math<span class="token punctuation">.</span><span class="token function">max</span><span class="token punctuation">(</span>ans<span class="token punctuation">,</span> val<span class="token punctuation">)</span>
  <span class="token punctuation">}</span>

  <span class="token keyword">return</span> ans
<span class="token punctuation">}</span>
</code></pre></div><h2 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h2>`,43),k={href:"https://juejin.cn/post/6919376064833667080",target:"_blank",rel:"noopener noreferrer"};function d(r,m){const s=t("ExternalLinkIcon");return p(),o("div",null,[i,n("p",null,[n("a",k,[e("React、Vue2、Vue3的三种Diff算法"),c(s)])])])}const w=a(u,[["render",d],["__file","4.4diff算法.html.vue"]]);export{w as default};
